# WRONG: treating the likelihood as a prior
# Prior should encode beliefs BEFORE data, not be data-dependent
def wrong_prior(theta, observed_heads, total_flips):
    # This is the likelihood, not a prior!
    return theta**observed_heads * (1-theta)**(total_flips - observed_heads)

# RIGHT: prior depends only on theta and your domain knowledge
from scipy.stats import beta

def correct_prior(theta):
    # Beta(2,2): mild belief that the coin is fair
    return beta.pdf(theta, a=2, b=2)  # pure prior — no data involved
